pub struct ReplyKeyboardMarkup {
pub mut:
	// Array of button rows, each represented by an Array of KeyboardButton objects
	keyboard [][]KeyboardButton
	// Optional. Requests clients to always show the keyboard when the regular keyboard is hidden. Defaults to false, in which case the custom keyboard can be hidden and opened with a keyboard icon.
	is_persistent bool @[omitempty]
	// Optional. Requests clients to resize the keyboard vertically for optimal fit (e.g., make the keyboard smaller if there are just two rows of buttons). Defaults to false, in which case the custom keyboard is always of the same height as the app's standard keyboard.
	resize_keyboard bool @[omitempty]
	// Optional. Requests clients to hide the keyboard as soon as it's been used. The keyboard will still be available, but clients will automatically display the usual letter-keyboard in the chat - the user can press a special button in the input field to see the custom keyboard again. Defaults to false.
	one_time_keyboard bool @[omitempty]
	// Optional. The placeholder to be shown in the input field when the keyboard is active; 1-64 characters
	input_field_placeholder string @[omitempty]
	// Optional. Use this parameter if you want to show the keyboard to specific users only. Targets: 1) users that are @mentioned in the text of the Message object; 2) if the bot's message is a reply to a message in the same chat and forum topic, sender of the original message.Example: A user requests to change the bot's language, bot replies to the request with a keyboard to select the new language. Other users in the group don't see the keyboard.
	selective bool @[omitempty]
}

// KeyboardButton This object represents one button of the reply keyboard. At most one of the fields other than text, icon_custom_emoji_id, and style must be used to specify the type of the button. For simple text buttons, String can be used instead of this object to specify the button text.
pub struct KeyboardButton {
pub mut:
	// Text of the button. If none of the fields other than text, icon_custom_emoji_id, and style are used, it will be sent as a message when the button is pressed.
	text string
	// Optional. Unique identifier of the custom emoji shown before the text of the button. Can only be used by bots that purchased additional usernames on Fragment or in the messages directly sent by the bot to private, group and supergroup chats if the owner of the bot has a Telegram Premium subscription.
	icon_custom_emoji_id string @[omitempty]
	// Optional. Style of the button. Must be one of “danger” (red), “success” (green) or “primary” (blue). If omitted, then an app-specific style is used.
	style string @[omitempty]
	// Optional. If specified, pressing the button will open a list of suitable users. Identifiers of selected users will be sent to the bot in a “users_shared” service message. Available in private chats only.
	request_users KeyboardButtonRequestUsers @[omitempty]
	// Optional. If specified, pressing the button will open a list of suitable chats. Tapping on a chat will send its identifier to the bot in a “chat_shared” service message. Available in private chats only.
	request_chat KeyboardButtonRequestChat @[omitempty]
	// Optional. If specified, pressing the button will ask the user to create and share a bot that will be managed by the current bot. Available for bots that enabled management of other bots in the @BotFather Mini App. Available in private chats only.
	request_managed_bot KeyboardButtonRequestManagedBot @[omitempty]
	// Optional. If True, the user's phone number will be sent as a contact when the button is pressed. Available in private chats only.
	request_contact bool @[omitempty]
	// Optional. If True, the user's current location will be sent when the button is pressed. Available in private chats only.
	request_location bool @[omitempty]
	// Optional. If specified, the user will be asked to create a poll and send it to the bot when the button is pressed. Available in private chats only.
	request_poll KeyboardButtonPollType @[omitempty]
	// Optional. If specified, the described Web App will be launched when the button is pressed. The Web App will be able to send a “web_app_data” service message. Available in private chats only.
	web_app WebAppInfo @[omitempty]
}

// KeyboardButtonRequestUsers This object defines the criteria used to request suitable users. Information about the selected users will be shared with the bot when the corresponding button is pressed. More about requesting users »
pub struct KeyboardButtonRequestUsers {
pub mut:
	// Signed 32-bit identifier of the request that will be received back in the UsersShared object. Must be unique within the message.
	request_id i64
	// Optional. Pass True to request bots, pass False to request regular users. If not specified, no additional restrictions are applied.
	user_is_bot bool @[omitempty]
	// Optional. Pass True to request premium users, pass False to request non-premium users. If not specified, no additional restrictions are applied.
	user_is_premium bool @[omitempty]
	// Optional. The maximum number of users to be selected; 1-10. Defaults to 1.
	max_quantity i64 @[omitempty]
	// Optional. Pass True to request the users' first and last names
	request_name bool @[omitempty]
	// Optional. Pass True to request the users' usernames
	request_username bool @[omitempty]
	// Optional. Pass True to request the users' photos
	request_photo bool @[omitempty]
}

// KeyboardButtonRequestChat This object defines the criteria used to request a suitable chat. Information about the selected chat will be shared with the bot when the corresponding button is pressed. The bot will be granted requested rights in the chat if appropriate. More about requesting chats ».
pub struct KeyboardButtonRequestChat {
pub mut:
	// Signed 32-bit identifier of the request, which will be received back in the ChatShared object. Must be unique within the message.
	request_id i64
	// Pass True to request a channel chat, pass False to request a group or a supergroup chat
	chat_is_channel bool
	// Optional. Pass True to request a forum supergroup, pass False to request a non-forum chat. If not specified, no additional restrictions are applied.
	chat_is_forum bool @[omitempty]
	// Optional. Pass True to request a supergroup or a channel with a username, pass False to request a chat without a username. If not specified, no additional restrictions are applied.
	chat_has_username bool @[omitempty]
	// Optional. Pass True to request a chat owned by the user. Otherwise, no additional restrictions are applied.
	chat_is_created bool @[omitempty]
	// Optional. A JSON-serialized object listing the required administrator rights of the user in the chat. The rights must be a superset of bot_administrator_rights. If not specified, no additional restrictions are applied.
	user_administrator_rights ChatAdministratorRights @[omitempty]
	// Optional. A JSON-serialized object listing the required administrator rights of the bot in the chat. The rights must be a subset of user_administrator_rights. If not specified, no additional restrictions are applied.
	bot_administrator_rights ChatAdministratorRights @[omitempty]
	// Optional. Pass True to request a chat with the bot as a member. Otherwise, no additional restrictions are applied.
	bot_is_member bool @[omitempty]
	// Optional. Pass True to request the chat's title
	request_title bool @[omitempty]
	// Optional. Pass True to request the chat's username
	request_username bool @[omitempty]
	// Optional. Pass True to request the chat's photo
	request_photo bool @[omitempty]
}

// KeyboardButtonRequestManagedBot This object defines the parameters for the creation of a managed bot. Information about the created bot will be shared with the bot using the update managed_bot and a Message with the field managed_bot_created.
pub struct KeyboardButtonRequestManagedBot {
pub mut:
	// Signed 32-bit identifier of the request. Must be unique within the message.
	request_id i64
	// Optional. Suggested name for the bot
	suggested_name string @[omitempty]
	// Optional. Suggested username for the bot
	suggested_username string @[omitempty]
}

// KeyboardButtonPollType This object represents type of a poll, which is allowed to be created and sent when the corresponding button is pressed.
pub struct KeyboardButtonPollType {
pub mut:
	// Optional. If quiz is passed, the user will be allowed to create only polls in the quiz mode. If regular is passed, only regular polls will be allowed. Otherwise, the user will be allowed to create a poll of any type.
	@type string @[json: 'type'; omitempty]
}

// ReplyKeyboardRemove Upon receiving a message with this object, Telegram clients will remove the current custom keyboard and display the default letter-keyboard. By default, custom keyboards are displayed until a new keyboard is sent by a bot. An exception is made for one-time keyboards that are hidden immediately after the user presses a button (see ReplyKeyboardMarkup). Not supported in channels and for messages sent on behalf of a business account.
pub struct ReplyKeyboardRemove {
pub mut:
	// Requests clients to remove the custom keyboard (user will not be able to summon this keyboard; if you want to hide the keyboard from sight but keep it accessible, use one_time_keyboard in ReplyKeyboardMarkup)
	remove_keyboard bool
	// Optional. Use this parameter if you want to remove the keyboard for specific users only. Targets: 1) users that are @mentioned in the text of the Message object; 2) if the bot's message is a reply to a message in the same chat and forum topic, sender of the original message.Example: A user votes in a poll, bot returns confirmation message in reply to the vote and removes the keyboard for that user, while still showing the keyboard with poll options to users who haven't voted yet.
	selective bool @[omitempty]
}

// InlineKeyboardMarkup This object represents an inline keyboard that appears right next to the message it belongs to.
pub struct InlineKeyboardMarkup {
pub mut:
	// Array of button rows, each represented by an Array of InlineKeyboardButton objects
	inline_keyboard [][]InlineKeyboardButton
}

// InlineKeyboardButton This object represents one button of an inline keyboard. Exactly one of the fields other than text, icon_custom_emoji_id, and style must be used to specify the type of the button.
pub struct InlineKeyboardButton {
pub mut:
	// Label text on the button
	text string
	// Optional. Unique identifier of the custom emoji shown before the text of the button. Can only be used by bots that purchased additional usernames on Fragment or in the messages directly sent by the bot to private, group and supergroup chats if the owner of the bot has a Telegram Premium subscription.
	icon_custom_emoji_id string @[omitempty]
	// Optional. Style of the button. Must be one of “danger” (red), “success” (green) or “primary” (blue). If omitted, then an app-specific style is used.
	style string @[omitempty]
	// Optional. HTTP or tg:// URL to be opened when the button is pressed. Links tg://user?id=<user_id> can be used to mention a user by their identifier without using a username, if this is allowed by their privacy settings.
	url string @[omitempty]
	// Optional. Data to be sent in a callback query to the bot when the button is pressed, 1-64 bytes
	callback_data string @[omitempty]
	// Optional. Description of the Web App that will be launched when the user presses the button. The Web App will be able to send an arbitrary message on behalf of the user using the method answerWebAppQuery. Available only in private chats between a user and the bot. Not supported for messages sent on behalf of a business account.
	web_app WebAppInfo @[omitempty]
	// Optional. An HTTPS URL used to automatically authorize the user. Can be used as a replacement for the Telegram Login Widget.
	login_url LoginUrl @[omitempty]
	// Optional. If set, pressing the button will prompt the user to select one of their chats, open that chat and insert the bot's username and the specified inline query in the input field. May be empty, in which case just the bot's username will be inserted. Not supported for messages sent in channel direct messages chats and on behalf of a business account.
	switch_inline_query string @[omitempty]
	// Optional. If set, pressing the button will insert the bot's username and the specified inline query in the current chat's input field. May be empty, in which case only the bot's username will be inserted.This offers a quick way for the user to open your bot in inline mode in the same chat - good for selecting something from multiple options. Not supported in channels and for messages sent in channel direct messages chats and on behalf of a business account.
	switch_inline_query_current_chat string @[omitempty]
	// Optional. If set, pressing the button will prompt the user to select one of their chats of the specified type, open that chat and insert the bot's username and the specified inline query in the input field. Not supported for messages sent in channel direct messages chats and on behalf of a business account.
	switch_inline_query_chosen_chat SwitchInlineQueryChosenChat @[omitempty]
	// Optional. Description of the button that copies the specified text to the clipboard
	copy_text CopyTextButton @[omitempty]
	// Optional. Description of the game that will be launched when the user presses the button.NOTE: This type of button must always be the first button in the first row.
	callback_game CallbackGame @[omitempty]
	// Optional. Specify True, to send a Pay button. Substrings “⭐” and “XTR” in the buttons's text will be replaced with a Telegram Star icon.NOTE: This type of button must always be the first button in the first row and can only be used in invoice messages.
	pay bool @[omitempty]
}

// LoginUrl This object represents a parameter of the inline keyboard button used to automatically authorize a user. Serves as a great replacement for the Telegram Login Widget when the user is coming from Telegram. All the user needs to do is tap/click a button and confirm that they want to log in: Telegram apps support these buttons as of version 5.7.
pub struct LoginUrl {
pub mut:
	// An HTTPS URL to be opened with user authorization data added to the query string when the button is pressed. If the user refuses to provide authorization data, the original URL without information about the user will be opened. The data added is the same as described in Receiving authorization data.NOTE: You must always check the hash of the received data to verify the authentication and the integrity of the data as described in Checking authorization.
	url string
	// Optional. New text of the button in forwarded messages
	forward_text string @[omitempty]
	// Optional. Username of a bot, which will be used for user authorization. See Setting up a bot for more details. If not specified, the current bot's username will be assumed. The url's domain must be the same as the domain linked with the bot. See Linking your domain to the bot for more details.
	bot_username string @[omitempty]
	// Optional. Pass True to request the permission for your bot to send messages to the user
	request_write_access bool @[omitempty]
}

// SwitchInlineQueryChosenChat This object represents an inline button that switches the current user to inline mode in a chosen chat, with an optional default inline query.
pub struct SwitchInlineQueryChosenChat {
pub mut:
	// Optional. The default inline query to be inserted in the input field. If left empty, only the bot's username will be inserted.
	query string @[omitempty]
	// Optional. True, if private chats with users can be chosen
	allow_user_chats bool @[omitempty]
	// Optional. True, if private chats with bots can be chosen
	allow_bot_chats bool @[omitempty]
	// Optional. True, if group and supergroup chats can be chosen
	allow_group_chats bool @[omitempty]
	// Optional. True, if channel chats can be chosen
	allow_channel_chats bool @[omitempty]
}

// CopyTextButton This object represents an inline keyboard button that copies specified text to the clipboard.
pub struct CopyTextButton {
pub mut:
	// The text to be copied to the clipboard; 1-256 characters
	text string
}

// CallbackQuery This object represents an incoming callback query from a callback button in an inline keyboard. If the button that originated the query was attached to a message sent by the bot, the field message will be present. If the button was attached to a message sent via the bot (in inline mode), the field inline_message_id will be present. Exactly one of the fields data or game_short_name will be present.
pub struct CallbackQuery {
pub mut:
	// Unique identifier for this query
	id string
	// Sender
	from User
	// Optional. Message sent by the bot with the callback button that originated the query
	message ?&MaybeInaccessibleMessage @[omitempty]
	// Optional. Identifier of the message sent via the bot in inline mode, that originated the query
	inline_message_id string @[omitempty]
	// Global identifier, uniquely corresponding to the chat to which the message with the callback button was sent. Useful for high scores in games.
	chat_instance string
	// Optional. Data associated with the callback button. Be aware that the message originated the query can contain no callback buttons with this data.
	data string @[omitempty]
	// Optional. Short name of a Game to be returned, serves as the unique identifier for the game
	game_short_name string @[omitempty]
}

// ForceReply Upon receiving a message with this object, Telegram clients will display a reply interface to the user (act as if the user has selected the bot's message and tapped 'Reply'). This can be extremely useful if you want to create user-friendly step-by-step interfaces without having to sacrifice privacy mode. Not supported in channels and for messages sent on behalf of a user account.
pub struct ForceReply {
pub mut:
	// Shows reply interface to the user, as if they manually selected the bot's message and tapped 'Reply'
	force_reply bool
	// Optional. The placeholder to be shown in the input field when the reply is active; 1-64 characters
	input_field_placeholder string @[omitempty]
	// Optional. Use this parameter if you want to force reply from specific users only. Targets: 1) users that are @mentioned in the text of the Message object; 2) if the bot's message is a reply to a message in the same chat and forum topic, sender of the original message.
	selective bool @[omitempty]
}

// ChatPhoto This object represents a chat photo.
pub struct ChatPhoto {
pub mut:
	// File identifier of small (160x160) chat photo. This file_id can be used only for photo download and only for as long as the photo is not changed.
	small_file_id string
	// Unique file identifier of small (160x160) chat photo, which is supposed to be the same over time and for different bots. Can't be used to download or reuse the file.
	small_file_unique_id string
	// File identifier of big (640x640) chat photo. This file_id can be used only for photo download and only for as long as the photo is not changed.
	big_file_id string
	// Unique file identifier of big (640x640) chat photo, which is supposed to be the same over time and for different bots. Can't be used to download or reuse the file.
	big_file_unique_id string
}

// ChatInviteLink Represents an invite link for a chat.
pub struct ChatInviteLink {
pub mut:
	// The invite link. If the link was created by another chat administrator, then the second part of the link will be replaced with “…”.
	invite_link string
	// Creator of the link
	creator User
	// True, if users joining the chat via the link need to be approved by chat administrators
	creates_join_request bool
	// True, if the link is primary
	is_primary bool
	// True, if the link is revoked
	is_revoked bool
	// Optional. Invite link name
	name string @[omitempty]
	// Optional. Point in time (Unix timestamp) when the link will expire or has been expired
	expire_date i64 @[omitempty]
	// Optional. The maximum number of users that can be members of the chat simultaneously after joining the chat via this invite link; 1-99999
	member_limit i64 @[omitempty]
	// Optional. Number of pending join requests created using this link
	pending_join_request_count i64 @[omitempty]
	// Optional. The number of seconds the subscription will be active for before the next payment
	subscription_period i64 @[omitempty]
	// Optional. The amount of Telegram Stars a user must pay initially and after each subsequent subscription period to be a member of the chat using the link
	subscription_price i64 @[omitempty]
}

// ChatAdministratorRights Represents the rights of an administrator in a chat.
pub struct ChatAdministratorRights {
pub mut:
	// True, if the user's presence in the chat is hidden
	is_anonymous bool
	// True, if the administrator can access the chat event log, get boost list, see hidden supergroup and channel members, report spam messages, ignore slow mode, and send messages to the chat without paying Telegram Stars. Implied by any other administrator privilege.
	can_manage_chat bool
	// True, if the administrator can delete messages of other users
	can_delete_messages bool
	// True, if the administrator can manage video chats
	can_manage_video_chats bool
	// True, if the administrator can restrict, ban or unban chat members, or access supergroup statistics
	can_restrict_members bool
	// True, if the administrator can add new administrators with a subset of their own privileges or demote administrators that they have promoted, directly or indirectly (promoted by administrators that were appointed by the user)
	can_promote_members bool
	// True, if the user is allowed to change the chat title, photo and other settings
	can_change_info bool
	// True, if the user is allowed to invite new users to the chat
	can_invite_users bool
	// True, if the administrator can post stories to the chat
	can_post_stories bool
	// True, if the administrator can edit stories posted by other users, post stories to the chat page, pin chat stories, and access the chat's story archive
	can_edit_stories bool
	// True, if the administrator can delete stories posted by other users
	can_delete_stories bool
	// Optional. True, if the administrator can post messages in the channel, approve suggested posts, or access channel statistics; for channels only
	can_post_messages bool @[omitempty]
	// Optional. True, if the administrator can edit messages of other users and can pin messages; for channels only
	can_edit_messages bool @[omitempty]
	// Optional. True, if the user is allowed to pin messages; for groups and supergroups only
	can_pin_messages bool @[omitempty]
	// Optional. True, if the user is allowed to create, rename, close, and reopen forum topics; for supergroups only
	can_manage_topics bool @[omitempty]
	// Optional. True, if the administrator can manage direct messages of the channel and decline suggested posts; for channels only
	can_manage_direct_messages bool @[omitempty]
	// Optional. True, if the administrator can edit the tags of regular members; for groups and supergroups only. If omitted defaults to the value of can_pin_messages.
	can_manage_tags bool @[omitempty]
}

// ChatMemberUpdated This object represents changes in the status of a chat member.
